const items = $input.all()[0].json.items;
const cropName = ($('On form submission').first().json.crop_name || '').toLowerCase();

const scored = items.map(video => {
  const views = parseInt(video.statistics?.viewCount || 0);
  const title = (video.snippet.title || '').toLowerCase();
  let score = views;
  if (title.includes(cropName)) score += 50000;
  if (title.includes('farming') || title.includes('cultivation')) score += 30000;
  const dur = video.contentDetails?.duration || '';
  const mins = parseInt(dur.match(/(\d+)M/)?.[1] || '0');
  const secs = dur.match(/(\d+)S/)?.[1] || '00';
  const duration = `${mins}:${secs.padStart(2, '0')}`;
  if (mins < 2 || mins > 30) score = 0;
  return {
    score,
    title: video.snippet.title,
    channel: video.snippet.channelTitle,
    thumbnail: video.snippet.thumbnails?.high?.url || video.snippet.thumbnails?.default?.url,
    description: (video.snippet.description || '').slice(0, 200),
    duration,
    youtube_url: `https://www.youtube.com/watch?v=${video.id}`
  };
});

const top15 = scored
  .filter(v => v.score > 0)
  .sort((a, b) => b.score - a.score)
  .slice(0, 15)
  .map((v, i) => ({
    ...v,
    batch: i < 4 ? 'initial' : 'load_more'
  }));

return [{ json: { videos: top15 } }];

const input = $input.all()[0].json;
const cropName = $('On form submission').first().json.crop_name || 'unknown';
const language = $('On form submission').first().json.language || 'unknown';

const fileName = `${cropName.toLowerCase()}_${language.toLowerCase()}.json`;

const formatVideos = (videos) => videos.map((v, index) => ({
  id: index + 1,
  batch: v.batch,
  title: v.title,
  channel: v.channel,
  duration: v.duration,
  thumbnail: {
    url: v.thumbnail,
    alt: `${v.title} - ${v.channel}`
  },
  description: v.description,
  link: {
    label: "Watch on YouTube",
    url: v.youtube_url
  }
}));

const initialVideos = input.videos.filter(v => v.batch === 'initial');
const loadMoreVideos = input.videos.filter(v => v.batch === 'load_more');

const payload = {
  meta: {
    crop: cropName,
    language: language,
    generated_at: new Date().toISOString().split('T')[0],
    total_videos: input.videos.length,
    initial_count: initialVideos.length,
    load_more_count: loadMoreVideos.length
  },
  initial: formatVideos(initialVideos),
  load_more: formatVideos(loadMoreVideos)
};

const fileName2 = fileName;

return [{
  json: {
    payload: JSON.stringify(payload, null, 2),
    fileName: fileName2
  }
}];
